        "@type": "Question",
        "name": "What is a breach of contract? ",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Failure to follow agreed contractual terms, procedures, or notice obligations."
        }
      },
      {
        "@type": "Question",
        "name": "What is an unlawful deduction from wages? ",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Pay withheld or reduced without contractual authority or the employee’s prior written consent."
        }
      },
      {
        "@type": "Question",
        "name": "Can employers ever deduct pay lawfully? ",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Yes, with clear contractual terms, employee consent, or statutory authority."
        }
      },
      {
        "@type": "Question",
        "name": "Do we need to consult before changing terms? ",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Usually yes. Consult, justify business reasons, and follow any contractual variation process."
        }
      },
      {
        "@type": "Question",
        "name": "What are time limits for Tribunal claims? ",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Typically three months less one day but ACAS Early Conciliation pauses time."
        }
      },
